def getAllPrimeFactors(n):
    if not isinstance(n, int) or n <= 0:
        return []
    if n == 1:
        return [1]
    factors = []
    # Handle factor 2
    while n % 2 == 0:
        factors.append(2)
        n //= 2
    # Handle odd factors
    f = 3
    while f * f <= n:
        while n % f == 0:
            factors.append(f)
            n //= f
        f += 2
    # Remaining prime factor
    if n > 1:
        factors.append(n)
    return factors

def getUniquePrimeFactorsWithCount(n):
    if not isinstance(n, int) or n <= 0:
        return [[], []]
    factors = getAllPrimeFactors(n)
    if not factors:
        return [[], []]
    primes = []
    counts = []
    prev = factors[0]
    cnt = 1
    for f in factors[1:]:
        if f == prev:
            cnt += 1
        else:
            primes.append(prev)
            counts.append(cnt)
            prev = f
            cnt = 1
    primes.append(prev)
    counts.append(cnt)
    return [primes, counts]

def getUniquePrimeFactorsWithProducts(n):
    if not isinstance(n, int) or n <= 0:
        return []
    factors = getAllPrimeFactors(n)
    if not factors:
        return []
    products = []
    prev = factors[0]
    cnt = 1
    for f in factors[1:]:
        if f == prev:
            cnt += 1
        else:
            products.append(prev ** cnt)
            prev = f
            cnt = 1
    products.append(prev ** cnt)
    return products

