import sys

def digit_value(c):
    if '0' <= c <= '9':
        return ord(c) - ord('0')
    elif 'A' <= c <= 'Z':
        return 10 + ord(c) - ord('A')
    elif 'a' <= c <= 'z':
        return 36 + ord(c) - ord('a')
    return -1

def is_polydivisible(n_str, b):
    if not n_str:
        return False
    current = 0
    for i, c in enumerate(n_str, start=1):
        d = digit_value(c)
        if d < 0 or d >= b:
            return False
        current = current * b + d
        if current % i != 0:
            return False
    return True

