def solve(S):
    if '=' not in S:
        return -1
    parts = S.split('=')
    if len(parts) != 2:
        return -1
    left_str = parts[0]
    result_str = parts[1]

    # Parse left_str
    i = 0
    num1_str = ''
    if i < len(left_str) and left_str[i] == '-':
        num1_str += '-'
        i += 1
    while i < len(left_str) and left_str[i] in '0123456789?':
        num1_str += left_str[i]
        i += 1
    if i >= len(left_str) or left_str[i] not in '+-*':
        return -1
    op = left_str[i]
    i += 1
    num2_str = left_str[i:]
    if not num2_str:
        return -1

    used = set(c for c in S if c.isdigit())

    def valid_num(s):
        if not s:
            return False, 0
        sign = 1
        digits = s
        if s[0] == '-':
            sign = -1
            digits = s[1:]
        if not digits:
            return False, 0
        if digits[0] == '0' and len(digits) > 1:
            return False, 0
        if not all(c.isdigit() for c in digits):
            return False, 0
        val = int(digits)
        if abs(val) > 1000000:
            return False, 0
        return True, sign * val

    for d in range(10):
        ds = str(d)
        if ds in used:
            continue
        n1 = num1_str.replace('?', ds)
        n2 = num2_str.replace('?', ds)
        nr = result_str.replace('?', ds)

        ok1, v1 = valid_num(n1)
        if not ok1:
            continue
        ok2, v2 = valid_num(n2)
        if not ok2:
            continue
        okr, vr = valid_num(nr)
        if not okr:
            continue

        if op == '+':
            leftv = v1 + v2
        elif op == '-':
            leftv = v1 - v2
        elif op == '*':
            leftv = v1 * v2
        else:
            continue

        if leftv == vr:
            return d
    return -1

