def factorize(n):
    factors = {}
    while n % 2 == 0:
        factors[2] = factors.get(2, 0) + 1
        n //= 2
    i = 3
    while i * i <= n:
        while n % i == 0:
            factors[i] = factors.get(i, 0) + 1
            n //= i
        i += 2
    if n > 1:
        factors[n] = 1
    return factors

def binom(n, r):
    if r > n - r:
        r = n - r
    res = 1
    for i in range(r):
        res = res * (n - i) // (i + 1)
    return res

