import sys

def gcd(a, b):
    while b:
        a, b = b, a % b
    return abs(a)

def egcd(a, b):
    old_r, r = a, b
    old_s, s = 1, 0
    old_t, t = 0, 1
    while r != 0:
        quotient = old_r // r
        old_r, r = r, old_r - quotient * r
        old_s, s = s, old_s - quotient * s
        old_t, t = t, old_t - quotient * t
    return old_r, old_s, old_t

def spinningRings(innerMax, outerMax):
    n = innerMax + 1
    m = outerMax + 1
    d = gcd(n, m)
    lcm_val = (n // d) * m
    mn = min(n, m)
    gg = gcd(d, 2)
    gamma = d // gg
    ans = lcm_val
    g_val, x, y = egcd(m, n)
    mod_group = n // g_val
    for ss in range(0, mn, gamma):
        s = ss
        target = (-s) % n
        diff = (target - s) % n
        if diff % g_val != 0:
            continue
        mult = diff // g_val
        x0 = (x * mult) % mod_group
        k0 = m * x0 + s
        k0 %= lcm_val
        if k0 == 0:
            k0 = lcm_val
        if k0 > 0 and k0 < ans:
            ans = k0
    return ans

