def floor_sqrt(num):
    if num == 0 or num == 1:
        return num
    left, right = 1, min(num // 2 + 1, 46341)
    while left <= right:
        mid = left + (right - left) // 2
        if mid * mid <= num:
            left = mid + 1
        else:
            right = mid - 1
    return right

def is_perfect_square(num):
    if num < 0:
        return False
    s = floor_sqrt(num)
    return s * s == num

def sum_of_squares(n):
    fs = floor_sqrt(n)
    if fs * fs == n:
        return 1
    for i in range(fs + 1):
        if is_perfect_square(n - i * i):
            return 2
    m = n
    while m % 4 == 0:
        m //= 4
    if m % 8 == 7:
        return 4
    return 3

